/**
 * Petshop Pack/Rinkinys Auto-Categories v1.0
 * Automatiškai priskiria teisingas kategorijas kuriant/išsaugant:
 *   - Daugiau=pigiau pack'us (turi _dp_base_product_id) -> paveldi bazinio kategorijas + DAUGIAU=PIGIAU (91)
 *   - Rinkinius (Mix and Match) -> paveldi iš komponentų dominuojančią produkto tipo kategoriją
 *     + Rinkiniai (679) + atitinkamą rinkinių subkategoriją (682/683/684)
 *
 * Speciali kategorija NIEKADA nepakeičia produkto kategorijos - tik PAPILDO.
 */

// Rinkinių subkategorijų mapping'as pagal komponentų tipą
function psac_rink_subcat($product_type_cat_name) {
  $n = mb_strtolower($product_type_cat_name);
  if (mb_strpos($n, 'konserv') !== false) return 682; // Konservų rinkiniai
  if (mb_strpos($n, 'skanėst') !== false || mb_strpos($n, 'skanest') !== false) return 683; // Skanėstų rinkiniai
  return null; // kramtalams neaišku iš tipo - liks be subkat auto (owner priskirs)
}

add_action('woocommerce_update_product', 'psac_apply_categories', 20, 1);
add_action('woocommerce_new_product', 'psac_apply_categories', 20, 1);

function psac_apply_categories($product_id) {
  // Rekursijos apsauga
  static $processing = array();
  if (isset($processing[$product_id])) return;
  $processing[$product_id] = true;

  $product = wc_get_product($product_id);
  if (!$product) { unset($processing[$product_id]); return; }

  $DAUGIAU_PIGIAU = 91;
  $RINKINIAI = 679;
  $special_cats = array(91, 679, 682, 683, 684); // specialios, nelaikom "produkto tipo"

  $existing = wp_get_post_terms($product_id, 'product_cat', array('fields'=>'ids'));
  $to_add = array();

  // === CASE 1: Daugiau=pigiau pack ===
  $base_id = $product->get_meta('_dp_base_product_id');
  if ($base_id) {
    $base_cats = wp_get_post_terms($base_id, 'product_cat', array('fields'=>'ids'));
    // bazinio produkto kategorijos (be specialiu) + DAUGIAU=PIGIAU
    $base_cats = array_diff($base_cats, $special_cats);
    $to_add = array_merge($base_cats, array($DAUGIAU_PIGIAU));
  }
  // === CASE 2: Rinkinys (Mix and Match) ===
  elseif ($product->get_type() === 'mix-and-match' && method_exists($product, 'get_contents')) {
    $contents = $product->get_contents();
    if (is_array($contents) && !empty($contents)) {
      // Skaiciuojam komponentu produkto-tipo kategoriju dazni
      $cat_freq = array();
      $cat_names = array();
      $total = 0;
      foreach ($contents as $item) {
        $pid = is_array($item) ? ($item['product_id'] ?? null) : null;
        if (!$pid) continue;
        $total++;
        $ccats = wp_get_post_terms($pid, 'product_cat', array('fields'=>'all'));
        foreach ($ccats as $ct) {
          if (in_array($ct->term_id, $special_cats)) continue;
          $cat_freq[$ct->term_id] = ($cat_freq[$ct->term_id] ?? 0) + 1;
          $cat_names[$ct->term_id] = $ct->name;
        }
      }
      if ($total > 0 && !empty($cat_freq)) {
        // Dominuojanti produkto tipo kategorija: >= 60% komponentu joje
        arsort($cat_freq);
        $dominant_id = null;
        foreach ($cat_freq as $cid => $freq) {
          // ieskom "produkto tipo" (pvz Konservai katems), praleidziam brendu kat (Miamor)
          $nm = mb_strtolower($cat_names[$cid]);
          $is_type = (mb_strpos($nm,'konserv')!==false || mb_strpos($nm,'skanėst')!==false 
                     || mb_strpos($nm,'skanest')!==false || mb_strpos($nm,'sausas')!==false
                     || mb_strpos($nm,'maistas')!==false);
          if ($is_type && $freq >= ($total * 0.6)) { $dominant_id = $cid; break; }
        }
        if ($dominant_id) {
          $to_add[] = $dominant_id;
          $to_add[] = $RINKINIAI;
          $sub = psac_rink_subcat($cat_names[$dominant_id]);
          if ($sub) $to_add[] = $sub;
        }
      }
    }
  }

  // Jei nera ka prideti - baigiam
  if (empty($to_add)) { unset($processing[$product_id]); return; }

  // Sujungiam su esamomis (PAPILDOM, ne pakeiciam), tik jei tikrai kazko truksta
  $new = array_values(array_unique(array_merge($existing, $to_add)));
  if (count(array_diff($new, $existing)) > 0) {
    wp_set_object_terms($product_id, $new, 'product_cat');
    wc_delete_product_transients($product_id);
  }

  unset($processing[$product_id]);
}
